	router.Get(options.BaseURL+"/system/diagnostics/db-tx", wrapper.DbTxDiagnostic)

	router.Get(options.BaseURL+"/system/live", wrapper.Liveness)

	router.Get(options.BaseURL+"/system/ready", wrapper.Readiness)

